/**
 * `wl-device-kit` — Work Louder device communication library.
 *
 * This package provides everything needed to discover, connect to, and
 * interact with Work Louder hardware (keyboards, macro pads, knobs) over
 * USB HID and serial.
 *
 * **Main entry points:**
 *
 * | Class | Purpose |
 * |---|---|
 * | {@link WLDeviceDiscovery} | Scan USB for connected Work Louder devices |
 * | {@link WLDeviceCommImpl}  | Open a transport connection (HID / serial) |
 * | {@link WLRPCApi}          | High-level typed RPC methods (status, files, lighting, …) |
 * | {@link WLRPCClient}       | Low-level JSON-RPC 2.0 request/response client |
 *
 * @example
 * ```ts
 * import {
 *   WLDeviceDiscovery,
 *   WLDeviceCommImpl,
 *   WLRPCApi,
 * } from "@worklouder/wl-device-kit";
 *
 * const discovery = new WLDeviceDiscovery();
 * const [device] = discovery.findWLDevices();
 *
 * const comm = new WLDeviceCommImpl();
 * await comm.connect(device);
 *
 * const api = new WLRPCApi(comm);
 * const status = await api.getDeviceStatus();
 * console.log(status.firmwareVersion);
 *
 * await comm.disconnect();
 * ```
 *
 * @packageDocumentation
 */
